import{_ as s,c as n,o as a,a5 as e}from"./chunks/framework.DwbewbAn.js";const E=JSON.parse('{"title":"FEDERATED引擎","description":"","frontmatter":{},"headers":[],"relativePath":"doc/数据库/Mysql/基础/引擎/federated/federated.md","filePath":"packages/doc/src/数据库/Mysql/基础/引擎/federated/federated.md","lastUpdated":1711622925000}'),l={name:"doc/数据库/Mysql/基础/引擎/federated/federated.md"},p=e(`<h1 id="federated引擎" tabindex="-1">FEDERATED引擎 <a class="header-anchor" href="#federated引擎" aria-label="Permalink to &quot;FEDERATED引擎&quot;">​</a></h1><ul><li><a href="https://dev.mysql.com/doc/refman/5.7/en/federated-storage-engine.html" target="_blank" rel="noreferrer">官方链接</a></li></ul><p>1.创建 <code>FEDERATED</code>表时，表定义相同，但数据的物理存储在远程服务器上处理。</p><p>一个<code>FEDERATED</code>表由两个元素组成：</p><ul><li><em>远程服务器</em>与数据库表，其又由表定义（存储中的 <code>.frm</code>文件）和相关联的表。远程表的表类型可以是远程<code>mysqld</code>服务器支持的任何类型，包括 <code>MyISAM</code>或<code>InnoDB</code>。</li><li><em>本地服务器</em>与数据库表，其中表定义相匹配，该远程服务器上的对应的表的。表定义存储在<code>.frm</code>文件中。但是，本地服务器上没有数据文件。相反，表定义包括一个指向远程表的连接字符串。</li></ul><p>在<code>FEDERATED</code>本地服务器上的表上执行查询和语句时 ，通常会在本地数据文件中插入、更新或删除信息的操作被发送到远程服务器执行，在那里它们更新远程服务器上的数据文件或从远程服务器返回匹配的行。</p><h2 id="_2-创建" tabindex="-1">2.创建 <a class="header-anchor" href="#_2-创建" aria-label="Permalink to &quot;2.创建&quot;">​</a></h2><p>1.使用 CONNECTION 创建联合表</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>CREATE TABLE federated_table (</span></span>
<span class="line"><span>    id     INT(20) NOT NULL AUTO_INCREMENT,</span></span>
<span class="line"><span>    name   VARCHAR(32) NOT NULL DEFAULT &#39;&#39;,</span></span>
<span class="line"><span>    other  INT(20) NOT NULL DEFAULT &#39;0&#39;,</span></span>
<span class="line"><span>    PRIMARY KEY  (id),</span></span>
<span class="line"><span>    INDEX name (name),</span></span>
<span class="line"><span>    INDEX other_key (other)</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>ENGINE=FEDERATED</span></span>
<span class="line"><span>DEFAULT CHARSET=latin1</span></span>
<span class="line"><span>CONNECTION=&#39;mysql://fed_user@remote_host:9306/federated/test_table&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>scheme://user_name[:password]@host_name[:port_num]/db_name/tbl_name</span></span>
<span class="line"><span>scheme：公认的连接协议。仅mysql支持作为此时的 scheme值。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>user_name：连接的用户名。此用户必须已在远程服务器上创建，并且必须具有适当的权限才能对远程表执行所需的操作（SELECT、 INSERT、 UPDATE等）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>password：（可选）对应的密码 user_name。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>host_name：远程服务器的主机名或 IP 地址。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>port_num：（可选）远程服务器的端口号。默认值为 3306。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>db_name: 保存远程表的数据库的名称。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>tbl_name: 远程表的名称。本地表和远程表的名称不必匹配。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>示例：</span></span>
<span class="line"><span>CONNECTION=&#39;mysql://username:password@hostname:port/database/tablename&#39;</span></span>
<span class="line"><span>CONNECTION=&#39;mysql://username@hostname/database/tablename&#39;</span></span>
<span class="line"><span>CONNECTION=&#39;mysql://username:password@hostname/database/tablename&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p>2.使用 CREATE SERVER 创建联合表</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>CREATE SERVER</span></span>
<span class="line"><span>server_name</span></span>
<span class="line"><span>FOREIGN DATA WRAPPER wrapper_name</span></span>
<span class="line"><span>OPTIONS (option [, option] ...)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CREATE SERVER fedlink</span></span>
<span class="line"><span>FOREIGN DATA WRAPPER mysql</span></span>
<span class="line"><span>OPTIONS (USER &#39;fed_user&#39;, HOST &#39;remote_host&#39;, PORT 9306, DATABASE &#39;federated&#39;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CREATE TABLE test_table (</span></span>
<span class="line"><span>    id     INT(20) NOT NULL AUTO_INCREMENT,</span></span>
<span class="line"><span>    name   VARCHAR(32) NOT NULL DEFAULT &#39;&#39;,</span></span>
<span class="line"><span>    other  INT(20) NOT NULL DEFAULT &#39;0&#39;,</span></span>
<span class="line"><span>    PRIMARY KEY  (id),</span></span>
<span class="line"><span>    INDEX name (name),</span></span>
<span class="line"><span>    INDEX other_key (other)</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>ENGINE=FEDERATED</span></span>
<span class="line"><span>DEFAULT CHARSET=latin1</span></span>
<span class="line"><span>CONNECTION=&#39;fedlink/test_table&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>scheme://user_name[:password]@host_name[:port_num]/db_name/tbl_name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><table><thead><tr><th style="text-align:left;">描述</th><th style="text-align:left;"><code>CONNECTION</code> 细绳</th><th style="text-align:left;"><a href="https://dev.mysql.com/doc/refman/5.7/en/create-server.html" target="_blank" rel="noreferrer"><code>CREATE SERVER</code></a> 选项</th><th style="text-align:left;"><code>mysql.servers</code> 柱子</th></tr></thead><tbody><tr><td style="text-align:left;">连接方案</td><td style="text-align:left;"><em><code>scheme</code></em></td><td style="text-align:left;"><code>wrapper_name</code></td><td style="text-align:left;"><code>Wrapper</code></td></tr><tr><td style="text-align:left;">远程用户</td><td style="text-align:left;"><em><code>user_name</code></em></td><td style="text-align:left;"><code>USER</code></td><td style="text-align:left;"><code>Username</code></td></tr><tr><td style="text-align:left;">远程密码</td><td style="text-align:left;"><em><code>password</code></em></td><td style="text-align:left;"><code>PASSWORD</code></td><td style="text-align:left;"><code>Password</code></td></tr><tr><td style="text-align:left;">远程主机</td><td style="text-align:left;"><em><code>host_name</code></em></td><td style="text-align:left;"><code>HOST</code></td><td style="text-align:left;"><code>Host</code></td></tr><tr><td style="text-align:left;">远程端口</td><td style="text-align:left;"><em><code>port_num</code></em></td><td style="text-align:left;"><code>PORT</code></td><td style="text-align:left;"><code>Port</code></td></tr><tr><td style="text-align:left;">远程数据库</td><td style="text-align:left;"><em><code>db_name</code></em></td><td style="text-align:left;"><code>DATABASE</code></td><td style="text-align:left;"><code>Db</code></td></tr></tbody></table>`,14),t=[p];function r(d,i,c,o,m,b){return a(),n("div",null,t)}const h=s(l,[["render",r]]);export{E as __pageData,h as default};
